  4→import { getBeamRenderData } from '@/geometry/beamGeometry';
  5→import { columnOutline } from '@/geometry/columnGeometry';
  6→import { landingOutline } from '@/geometry/landingGeometry';
  7→import { getSectionCutRenderData } from '@/geometry/sectionCutGeometry';
  8→import { getSlabRenderData } from '@/geometry/slabGeometry';
  9→import { getStairRenderData } from '@/geometry/stairGeometry';
 10→import { doorOutlineOnWall, windowOutlineOnWall } from '@/geometry/wallGeometry';
 11→import { getWallRenderData } from '@/geometry/wallColumnGeometry';
 12→import { buildProjectSectionScene } from '@/sections/scene';
 13→
 14→const PLAN_PADDING = 1500;
 15→const VERTICAL_PADDING = 700;
 16→const TOP_PADDING = 1100;
 17→
 18→function boundsFromPoints(points = [], fallback = { minX: -1000, maxX: 1000, minY: -1000, maxY: 1000 }) {
 19→  if (!points.length) return fallback;
 20→  return {
 21→    minX: Math.min(...points.map((point) => point.x)),
 22→    maxX: Math.max(...points.map((point) => point.x)),
 23→    minY: Math.min(...points.map((point) => point.y)),
 24→    maxY: Math.max(...points.map((point) => point.y)),
 25→  };
 26→}
 27→
 28→function expandBounds(bounds, paddingX, paddingY = paddingX) {
 29→  return {
 30→    minX: bounds.minX - paddingX,
 31→    maxX: bounds.maxX + paddingX,
 32→    minY: bounds.minY - paddingY,
 33→    maxY: bounds.maxY + paddingY,
 34→  };
 35→}
 36→
 37→function collectPlanPoints(floor) {
 38→  const points = [];
 39→
 40→  for (const wall of floor.walls || []) {
 41→    points.push(...(getWallRenderData(wall, floor.columns || []).outline || []));
 42→  }
 43→  for (const room of floor.rooms || []) {
 44→    points.push(...(room.points || []));
 45→  }
 46→  for (const beam of floor.beams || []) {
 47→    const renderData = getBeamRenderData(beam, floor.columns || []);
 48→    if (renderData?.outline) points.push(...renderData.outline);
 49→  }
 50→  for (const stair of floor.stairs || []) {
 51→    const renderData = getStairRenderData(stair);
 52→    if (renderData?.outline) points.push(...renderData.outline);
 53→  }
 54→  for (const landing of floor.landings || []) {
 55→    points.push(...landingOutline(landing));
 56→  }
 57→  for (const column of floor.columns || []) {
 58→    points.push(...columnOutline(column));
 59→  }
 60→  for (const slab of (floor.slabs || [])) {
 61→    const rd = getSlabRenderData(slab);
 62→    if (rd?.boundaryPoints) points.push(...rd.boundaryPoints);
 63→  }
 64→  for (const sc of (floor.sectionCuts || [])) {
 65→    points.push(sc.startPoint, sc.endPoint);
 66→    const renderData = getSectionCutRenderData(sc);
 67→    if (renderData?.arrow) {
 68→      points.push(renderData.arrow.shaftStart, renderData.arrow.shaftEnd, renderData.arrow.headA, renderData.arrow.headB);
 69→    }
 70→  }
 71→
 72→  for (const door of floor.doors || []) {
 73→    const wall = (floor.walls || []).find((entry) => entry.id === door.wallId);
 74→    if (!wall) continue;
 75→    const outline = doorOutlineOnWall(wall, door);
 76→    points.push(outline.p1, outline.p2, outline.p3, outline.p4);
 77→  }
 78→
 79→  for (const windowItem of floor.windows || []) {
 80→    const wall = (floor.walls || []).find((entry) => entry.id === windowItem.wallId);
 81→    if (!wall) continue;
 82→    const outline = windowOutlineOnWall(wall, windowItem);
 83→    points.push(outline.p1, outline.p2, outline.p3, outline.p4);
 84→  }
 85→
 86→  return points;
 87→}
 88→
 89→function buildPlanSource(floor) {
 90→  if (!floor) {
 91→    return {
 92→      kind: 'empty',
 93→      title: 'Plan',
 94→      message: 'Missing floor.',
 95→      bounds: { minX: 0, maxX: 2000, minY: 0, maxY: 1500 },
 96→    };
 97→  }
 98→
 99→  const geometryBounds = expandBounds(boundsFromPoints(collectPlanPoints(floor)), PLAN_PADDING);
100→
101→  return {
102→    kind: 'plan',
103→    title: `${floor.name} Plan`,
104→    floor,
105→    bounds: geometryBounds,
106→  };
107→}
108→
109→function sceneBoundsToRenderBounds(scene) {
110→  return {
111→    minX: scene.bounds.minX - VERTICAL_PADDING,
112→    maxX: scene.bounds.maxX + VERTICAL_PADDING,
113→    minY: -scene.bounds.maxZ - TOP_PADDING,
114→    maxY: -scene.bounds.minZ + VERTICAL_PADDING,
115→  };
116→}
117→
118→function buildSectionSource(project, floor, sourceRefId) {
119→  const cuts = floor?.sectionCuts || [];
120→  const sectionCut = sourceRefId
121→    ? cuts.find(s => s.id === sourceRefId)
122→    : cuts[0] || null;
123→
124→  if (!sectionCut) {
125→    return {
126→      kind: 'empty',
127→      title: 'Section',
128→      message: 'No section cut on this floor.',
129→      bounds: { minX: 0, maxX: 2000, minY: -3000, maxY: 1000 },
130→    };
131→  }
132→
133→  const scene = buildProjectSectionScene(project, floor.id, sectionCut.id);
134→  return {
135→    kind: 'section',
136→    title: sectionCut.label || 'Section',
137→    floor,
138→    scene,
139→    bounds: sceneBoundsToRenderBounds(scene),
140→  };
141→}
142→
143→function buildElevationSource(project, floor, sourceView) {
144→  if (!floor) {
145→    return {
146→      kind: 'empty',
147→      title: 'Elevation',
148→      message: 'Missing floor.',
149→      bounds: { minX: 0, maxX: 2000, minY: -3000, maxY: 1000 },
150→    };
151→  }
152→
153→  const scene = buildProjectElevationScene(project, floor.id, sourceView);
154→  const annotationScene = buildElevationAnnotationScene(floor, scene);
155→
156→  return {
157→    kind: 'elevation',
158→    title: scene.title,
159→    floor,
160→    viewMode: sourceView,
161→    scene,
162→    annotationScene,
163→    bounds: sceneBoundsToRenderBounds(scene),
164→  };
165→}
166→
167→function build3DPreviewSource(project, floor) {
168→  if (!floor) {
169→    return {
170→      kind: 'empty',
171→      title: 'Axonometric View',
172→      message: 'Missing floor.',
173→      bounds: { minX: 0, maxX: 2000, minY: 0, maxY: 1500 },
174→    };
175→  }
176→
177→  // Use 16:10 aspect ratio matching render resolution (1600x1000).
178→  // At scale 100, this fills a 160x100mm viewport on paper.
179→  const imageWidth = 16000;
180→  const imageHeight = 10000;
181→
182→  return {
183→    kind: '3d_preview',
184→    title: 'Axonometric View',
185→    project,
186→    activeFloorId: floor.id,
187→    bounds: {
188→      minX: 0,
189→      maxX: imageWidth,
190→      minY: 0,
191→      maxY: imageHeight,
192→    },
193→  };
194→}
195→
196→export function resolveSheetViewportSource(project, viewport) {
197→  const defaultFloorId = getDefaultActiveFloorId(project, viewport.sourceFloorId);
198→  const floor = resolveProjectFloor(project, defaultFloorId);
199→
200→  switch (viewport.sourceView) {
201→    case '3d_preview':
202→      return build3DPreviewSource(project, floor);
203→    case 'section':
204→      return buildSectionSource(project, floor, viewport.sourceRefId);
205→    case 'elevation_front':
206→    case 'elevation_rear':
207→    case 'elevation_left':
208→    case 'elevation_right':
209→      return buildElevationSource(project, floor, viewport.sourceView);
210→    case 'plan':
211→    default:
212→      return buildPlanSource(floor);
213→  }
214→}
215→
216→export function getViewportSourceLabel(sourceView) {
217→  switch (sourceView) {
218→    case '3d_preview':
219→      return 'Axonometric View';
220→    case 'section':
221→      return 'Section';
222→    case 'elevation_front':
223→      return 'Front Elevation';
224→    case 'elevation_rear':
225→      return 'Rear Elevation';
226→    case 'elevation_left':
227→      return 'Left Elevation';
228→    case 'elevation_right':
229→      return 'Right Elevation';
230→    case 'plan':
231→    default:
232→      return 'Plan';
233→  }
234→}
