 84→function buildContentTransform(viewport, source, contentRect) {
 85→  const bounds = source.bounds || { minX: 0, maxX: 1000, minY: 0, maxY: 1000 };
 86→  const sourceWidth = Math.max(1, bounds.maxX - bounds.minX);
 87→  const sourceHeight = Math.max(1, bounds.maxY - bounds.minY);
 88→  const scale = source.kind === '3d_preview'
 89→    ? Math.min(contentRect.width / sourceWidth, contentRect.height / sourceHeight)
 90→    : (1 / resolveViewportScale(viewport));
 91→
 92→  const drawnWidth = sourceWidth * scale;
 93→  const drawnHeight = sourceHeight * scale;
 94→  const translateX = (contentRect.width - drawnWidth) / 2 - bounds.minX * scale;
 95→  const translateY = (contentRect.height - drawnHeight) / 2 - bounds.minY * scale;
 96→
 97→  return {
 98→    scale,
 99→    translateX,
100→    translateY,
101→  };
102→}
