 50→export default function SvgCanvas() {
 51→  const svgRef = useRef(null);
 52→  const isPanning = useRef(false);
 53→  const lastPanPos = useRef({ x: 0, y: 0 });
 54→  const spaceHeld = useRef(false);
 55→  const cursorPosRef = useRef({ x: 0, y: 0 });
 56→  const [cursorPos, setCursorPos] = useState({ x: 0, y: 0 });
 57→
 58→  const { project, dispatch, getFloor } = useProject();
 59→  const editor = useEditor();
 60→  const {
 61→    activeTool, selectedId, selectedType, toolState,
 62→    viewport, showGrid, snapEnabled, activeFloorId, statusMessage, viewMode, activeSectionCutId,
 63→    regionSelection, pastePreview, maximizedPanel,
 64→    dispatch: editorDispatch,
 65→  } = editor;
 66→
 67→  const floor = getFloor(activeFloorId);
 68→  const {
 69→    copySelection,
 70→    cutSelection,
 71→    beginPaste,
 72→    updatePastePreview,
 73→    cancelPaste,
 74→    placePaste,
 75→    previewContent,
 76→  } = usePlanClipboardController();
 77→
 78→  const tool = useEditorTool({
 79→    activeTool,
 80→    dispatch,
 81→    editorDispatch,
 82→    project,
 83→    getFloor,
 84→    activeFloorId,
 85→    viewport,
 86→    snapEnabled,
 87→    selectedId,
 88→    selectedType,
 89→    toolState,
 90→    viewMode,
 91→  });
 92→
 93→  const getModelPos = useCallback((e) => {
 94→    const rect = svgRef.current.getBoundingClientRect();
 95→    return screenToModel(e.clientX, e.clientY, viewport, rect);
 96→  }, [viewport]);
 97→
 98→  const handleMouseDown = useCallback((e) => {
 99→    // Middle mouse or space+left for pan
100→    if (e.button === 1 || (e.button === 0 && spaceHeld.current)) {
101→      isPanning.current = true;
102→      lastPanPos.current = { x: e.clientX, y: e.clientY };
103→      e.preventDefault();
104→      return;
105→    }
106→
107→    const modelPos = getModelPos(e);
108→    if (pastePreview?.active && e.button === 0) {
109→      placePaste(modelPos);
110→      return;
111→    }
112→    tool.onMouseDown(modelPos, e);
113→  }, [getModelPos, pastePreview, placePaste, tool]);
114→
115→  const handleMouseMove = useCallback((e) => {
116→    if (isPanning.current) {
117→      const dx = e.clientX - lastPanPos.current.x;
118→      const dy = e.clientY - lastPanPos.current.y;
119→      editorDispatch({ type: 'PAN', dx, dy });
120→      lastPanPos.current = { x: e.clientX, y: e.clientY };
121→      return;
122→    }
123→
124→    const modelPos = getModelPos(e);
125→    cursorPosRef.current = modelPos;
126→    setCursorPos(modelPos);
127→    if (pastePreview?.active) {
128→      updatePastePreview(modelPos);
129→      return;
130→    }
131→    tool.onMouseMove(modelPos, e);
132→  }, [getModelPos, pastePreview, tool, updatePastePreview, editorDispatch]);
133→
134→  const handleMouseUp = useCallback((e) => {
135→    if (isPanning.current) {
136→      isPanning.current = false;
137→      return;
138→    }
139→    if (pastePreview?.active) return;
140→    const modelPos = getModelPos(e);
141→    tool.onMouseUp(modelPos, e);
142→  }, [getModelPos, pastePreview, tool]);
143→
144→  const handleDoubleClick = useCallback((e) => {
145→    if (pastePreview?.active) return;
146→    const modelPos = getModelPos(e);
147→    tool.onDoubleClick(modelPos, e);
148→  }, [getModelPos, pastePreview, tool]);
149→
150→  const handleWheel = useCallback((e) => {
151→    e.preventDefault();
152→    const rect = svgRef.current.getBoundingClientRect();
153→    const mouseX = e.clientX - rect.left;
154→    const mouseY = e.clientY - rect.top;
155→
156→    const direction = e.deltaY < 0 ? 1 : -1;
157→    const factor = direction > 0 ? ZOOM_FACTOR : 1 / ZOOM_FACTOR;
158→    const newZoom = Math.max(MIN_ZOOM, Math.min(MAX_ZOOM, viewport.zoom * factor));
159→
160→    // Zoom centered on cursor
161→    const newPanX = mouseX - (mouseX - viewport.panX) * (newZoom / viewport.zoom);
162→    const newPanY = mouseY - (mouseY - viewport.panY) * (newZoom / viewport.zoom);
163→
164→    editorDispatch({ type: 'ZOOM', zoom: newZoom, panX: newPanX, panY: newPanY });
165→  }, [viewport, editorDispatch]);
166→
167→  useEffect(() => {
168→    if (!statusMessage) return undefined;
