170→    const timer = window.setTimeout(() => {
171→      editorDispatch({ type: 'CLEAR_STATUS_MESSAGE' });
172→    }, 2500);
173→
174→    return () => window.clearTimeout(timer);
175→  }, [statusMessage, editorDispatch]);
176→
177→  useEffect(() => {
178→    const handleKeyDown = (e) => {
179→      if (isTypingTarget(e.target)) return;
180→
181→      if (e.key === ' ') {
182→        spaceHeld.current = true;
183→        e.preventDefault();
184→      }
185→
186→      if ((e.ctrlKey || e.metaKey) && viewMode === 'plan') {
187→        const key = e.key.toLowerCase();
