222→            return;
223→          case 'b':
224→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.BEAM });
225→            return;
226→          case 't':
227→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.STAIR });
228→            return;
229→          case 'q':
230→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SECTION });
231→            return;
232→          case 's':
233→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SLAB });
234→            return;
235→          case 'r':
236→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.ROOM });
237→            return;
238→          case 'd':
239→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.DOOR });
240→            return;
241→          case 'n':
242→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.WINDOW });
243→            return;
244→          case 'c':
245→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.COLUMN });
246→            return;
247→          case 'l':
248→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.LANDING });
249→            return;
250→          case 'f':
251→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.FIXTURE });
252→            editorDispatch({ type: 'UPDATE_TOOL_STATE', payload: { fixtureType: 'kitchenTop', previewRotation: 0 } });
253→            return;
254→        }
255→      }
256→
257→      tool.onKeyDown(e);
258→    };
259→
260→    const handleKeyUp = (e) => {
261→      if (isTypingTarget(e.target)) return;
262→
263→      if (e.key === ' ') {
264→        spaceHeld.current = false;
265→      }
266→    };
267→
268→    window.addEventListener('keydown', handleKeyDown);
269→    window.addEventListener('keyup', handleKeyUp);
270→    return () => {
271→      window.removeEventListener('keydown', handleKeyDown);
272→      window.removeEventListener('keyup', handleKeyUp);
273→    };
274→  }, [beginPaste, cancelPaste, copySelection, cutSelection, pastePreview?.active, tool, editorDispatch, viewMode]);
275→
276→  // Prevent default context menu on SVG
277→  useEffect(() => {
278→    const svg = svgRef.current;
279→    if (!svg) return;
280→    const prevent = (e) => e.preventDefault();
281→    svg.addEventListener('contextmenu', prevent);
282→    svg.addEventListener('wheel', handleWheel, { passive: false });
283→    return () => {
284→      svg.removeEventListener('contextmenu', prevent);
285→      svg.removeEventListener('wheel', handleWheel);
286→    };
287→  }, [handleWheel]);
288→
289→  const cursor = spaceHeld.current ? 'grab' : pastePreview?.active ? 'copy' : tool.getCursor();
290→  const zoomPercent = Math.round(viewport.zoom * 1000);
291→  const displayedTool = viewMode.startsWith('elevation_') ? 'select' : activeTool;
292→  const isCanvasMaximized = maximizedPanel === 'canvas';
