229→export default function FixtureRenderer({ fixtures }) {
230→  return (
231→    <g className="fixtures">
232→      {fixtures.map(fixture => {
233→        const outline = fixtureOutline(fixture);
234→        const points = outline.map(p => `${p.x},${p.y}`).join(' ');
235→        const gradFill = `url(#grad-${fixture.fixtureType})`;
236→        return (
237→          <g key={fixture.id} filter="url(#fixture-shadow)">
238→            <polygon
239→              data-id={fixture.id}
240→              data-type="fixture"
241→              points={points}
242→              fill={gradFill}
243→              stroke="#8A7D6B"
244→              strokeWidth={1.5}
245→              vectorEffect="non-scaling-stroke"
246→            />
247→            <FixtureDetails fixture={fixture} />
248→          </g>
249→        );
250→      })}
251→    </g>
252→  );
253→}
